Here's a comprehensive formula sheet for CBSE Class 11 Chemistry - Environmental Chemistry:

```json
[
  {
    "name": "Dobson Unit",
    "formula": "DU = (100 * NO2 / (p * 0.00001))",
    "variables": {
      "DU": "Dobson Unit",
      "NO2": "Nitrogen dioxide concentration (mol/m3)",
      "p": "Atmospheric pressure (Pa)"
    },
    "units": "DU",
    "notes": "A unit to measure the amount of nitrogen dioxide in the atmosphere"
  },
  {
    "name": "Atmospheric Half Life",
    "formula": "t1/2 = 0.693 * M / k",
    "variables": {
      "t1/2": "Atmospheric half life (time)",
      "M": "Atmospheric concentration of pollutant (mol/m3)",
      "k": "Rate constant for atmospheric degradation (s-1)"
    },
    "units": "s",
    "notes": "Calculates the time required for the atmospheric concentration of a pollutant to decrease by half"
  },
  {
    "name": "Atmospheric Lifetime",
    "formula": "τ = M / (k * c)",
    "variables": {
      "τ": "Atmospheric lifetime (time)",
      "M": "Atmospheric concentration of pollutant (mol/m3)",
      "k": "Rate constant for atmospheric degradation (m3/mol*s)",
      "c": "Atmospheric flow rate (m3/s)"
    },
    "units": "s",
    "notes": "Calculates the average time a pollutant remains in the atmosphere"
  },
  {
    "name": "BOD (Biochemical Oxygen Demand)",
    "formula": "BOD = (O2 consumed / V * t)",
    "variables": {
      "BOD": "Biochemical oxygen demand (mg/L)",
      "O2 consumed": "Amount of oxygen consumed by microorganisms (mg/L)",
      "V": "Volume of sample (L)",
      "t": "Time (days)"
    },
    "units": "mg/L",
    "notes": "A measure of the amount of oxygen required by microorganisms to break down organic matter"
  },
  {
    "name": "COD (Chemical Oxygen Demand)",
    "formula": "COD = (O2 required / V * 8.34)",
    "variables": {
      "COD": "Chemical oxygen demand (mg/L)",
      "O2 required": "Amount of oxygen required by chemical oxidation (mg/L)",
      "V": "Volume of sample (L)",
      "8.34": "Conversion factor from mg/L to mg O2/L"
    },
    "units": "mg/L",
    "notes": "A measure of the amount of oxygen required to oxidize organic and inorganic compounds"
  },
  {
    "name": "Thermodynamic Diagram",
    "formula": "ΔH = ΔU + Δ(pV)",
    "variables": {
      "ΔH": "Enthalpy change (J/mol)",
      "ΔU": "Internal energy change (J/mol)",
      "Δ(pV)": "Change in pressure-volume work (J/mol)",
      "p": "Pressure (Pa)",
      "V": "Volume (m3)"
    },
    "units": "J/mol",
    "notes": "Relates the change in enthalpy to the change in internal energy and the change in pressure-volume work"
  },
  {
    "name": "Henry's Law",
    "formula": "p = k * C",
    "variables": {
      "p": "Partial pressure of a gas (Pa)",
      "k": "Henry's Law constant (Pa*m3/mol)",
      "C": "Concentration of the gas in solution (mol/m3)"
    },
    "units": "Pa",
    "notes": "Describes the relationship between the partial pressure of a gas and its concentration in a solution"
  },
  {
    "name": "Vant Hoff Equation",
    "formula": "K = K0 * e^(-ΔH/RT)",
    "variables": {
      "K": "Equilibrium constant at temperature T (K)",
      "K0": "Equilibrium constant at infinite temperature (K)",
      "ΔH": "Enthalpy change (J/mol)",
      "R": "Gas constant (J/mol*K)",
      "T": "Temperature (K)"
    },
    "units": "K",
    "notes": "Relates the equilibrium constant at a given temperature to the enthalpy change and the temperature"
  },
  {
    "name": "Arrhenius Equation",
    "formula": "k = Ae^(-Ea/RT)",
    "variables": {
      "k": "Rate constant (s-1)",
      "A": "Pre-exponential factor (s-1)",
      "Ea": "Activation energy (J/mol)",
      "R": "Gas constant (J/mol*K)",
      "T": "Temperature (K)"
    },
    "units": "s-1",
    "notes": "Describes the relationship between the rate constant and the temperature"
  }
]
